function parseAny(x) {
  if (typeof x === 'number') return x;

  if (typeof x === 'string') {
    let s = x.trim();

    // bỏ dấu % và khoảng trắng
    s = s.replace(/\s+/g, '').replace('%', '');

    // Các trường hợp số thập phân dùng dấu phẩy:
    // - "52,2"
    // - "1.234,5" (dấu . là phân tách hàng nghìn)
    // Quy tắc: bỏ hết dấu chấm, đổi dấu phẩy thành chấm.
    if (/,/.test(s)) {
      s = s.replace(/\./g, '').replace(',', '.');
    }

    // Nếu chỉ có dấu chấm (thập phân chuẩn) thì giữ nguyên
    const n = Number(s);
    if (!Number.isNaN(n)) return n;
    return undefined;
  }

  // object có thuộc tính pumpSpeed (có thể là "52,2")
  if (x && typeof x === 'object') {
    const cand = x.pumpSpeed ?? x.value ?? x.speed;
    return parseAny(cand);
  }

  return undefined;
}

let v = parseAny(msg.payload);
if (v === undefined) return null;

// Giới hạn 0..100 và làm tròn 1 chữ số thập phân
v = Math.max(0, Math.min(100, v));
msg.payload = Math.round(v * 10) / 10;

return msg;
